import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return None

    candidate_nodes = np.array([node for node in unvisited_nodes if node not in truck_nodes and node != depot_node])

    if len(candidate_nodes) == 0:
        return None

    scores = np.zeros(len(candidate_nodes))
    for i, node in enumerate(candidate_nodes):
        distance_to_depot = distance_matrix[node][depot_node]
        distance_from_current = distance_matrix[current_node][node]
        if distance_from_current == 0:
            distance_from_current = 1  # To avoid division by zero
        scores[i] = distance_to_depot * (1 / (distance_from_current ** 2))

    next_node = candidate_nodes[np.argmax(scores)]

    return next_node

import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if unvisited_nodes.size == 0:
        return None

    candidate_nodes = np.array([node for node in unvisited_nodes if node not in truck_nodes])
    if candidate_nodes.size == 0:
        return None

    candidate_scores = np.zeros(candidate_nodes.shape[0])
    for i, node in enumerate(candidate_nodes):
        entropy_values = np.zeros(candidate_nodes.shape[0])
        for j, other_node in enumerate(candidate_nodes):
            if node != other_node:
                entropy_values[j] = distance_matrix[node, other_node]
        # Calculate entropy score as inverse of distance spread regularity
        if entropy_values.std() == 0:
            candidate_scores[i] = np.inf  # Avoid division by zero, assign high cost
        else:
            candidate_scores[i] = distance_matrix[current_node, node] / entropy_values.std()

    # Select candidate with the lowest entropy score
    next_node = candidate_nodes[np.argmin(candidate_scores)]

    return next_node
